<html>
<head>
    <title>Play WASM Raw Binary Data as Sound</title>
</head>
<body>
    <button id="playButton">Play Raw Data Sound</button>

    <script>
        document.getElementById('playButton').addEventListener('click', function() {
            // Initialize the AudioContext
            var audioContext = new (window.AudioContext || window.webkitAudioContext)();

            // Fetch the WebAssembly binary as an ArrayBuffer
            fetch('path_to_your_file.wasm')
                .then(function(response) {
                    return response.arrayBuffer();
                })
                .then(function(arrayBuffer) {
                    // Create an audio buffer
                    var audioBuffer = audioContext.createBuffer(1, arrayBuffer.byteLength, audioContext.sampleRate);
                    var bufferData = audioBuffer.getChannelData(0);
                    var fileData = new Uint8Array(arrayBuffer);

                    // Convert the raw byte data to PCM audio data (assuming 8-bit samples)
                    for (var i = 0; i < fileData.length; i++) {
                        var unsignedSample = fileData[i];            // Range 0 to 255
                        var normalizedSample = (unsignedSample / 128) - 1; // Normalize to -1 to 1
                        bufferData[i] = normalizedSample;            // Assign to bufferData
                    }

                    // Set up the audio buffer for playback
                    var source = audioContext.createBufferSource();
                    source.buffer = audioBuffer;
                    source.connect(audioContext.destination);

                    // Play the sound
                    source.start();

                    // Handle stopping the noise when the webpage is closed or navigated away from
                    window.addEventListener('beforeunload', function() {
                        source.stop();
                    });
                })
                .catch(function(error) {
                    console.error('Error fetching or decoding the WASM file:', error);
                });
        });
    </script>
</body>
</html>
```

